var b="url",c="入库单.html",d="generationDate",e=new Date(1781590691045.21),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="axhubclickvalue",s="page",t="packageId",u="a2266c5f90154511ba53607cbe5fa935",v="type",w="Axure:Page",x="入库单",y="notes",z="annotations",A="fn",B="1",C="ownerId",D="fd0dff1ff8904698a52e423acf7299a9",E="label",F="(文本框)",G="说明",H="<p><span>1.提示字：成品入库单/关联单据/款号</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.支持对“成品入库单”、“关联单据”、“款号”列的模糊查询</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.右侧含&quot;×&quot;的快捷清除按钮</span></p><p><span>2.点击【搜索】后返回查询结果</span></p>",I="2",J="7ae764b8c1bf45fba8ce0d5e3c987696",K="关联单据",L="<p><span>1.默认提示字“请选择客户”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.展示全部数据</span></p><p><span>2.数据源：[基础数据系统&gt;&gt;客户资料]的客户</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.支持对&quot;客户名称&quot;的模糊搜索</span></p><p><span>3.右侧含“×”的快捷清除按钮</span></p><p><span>4.选中/清空：直接返回结果</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.针对&quot;客户&quot;列进行检索</span></p>",M="3",N="13143761a3134666a121690680d2c0b9",O="(下拉列表)",P="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">下拉选项</span></p><p><span>1.未选中提示字：入库类型</span></p><p><span>2.可选性</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.生产入库</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.生产退货</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; c.采购入库</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; d.直接入库</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; e.</span><span style=\"color:#D9001B;\">待规划…</span></p><p><span>3.右侧含“×‘的快捷清空按钮</span></p><p><span>4.选中或清空后</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.将对应选中项值返回当前下拉域</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.立即针对“入库类型”列返回筛选结果</span></p>",Q="4",R="83339824353741849f55aabb61089a8a",S="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">下拉选项</span></p><p><span>1.未选中提示字：入库方式</span></p><p><span>2.可选性</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.箱装</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.散装</span></p><p><span>3.右侧含“×‘的快捷清空按钮</span></p><p><span>4.选中或清空后</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.将对应选中项值返回当前下拉域</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.立即针对“入库方式”列返回筛选结果</span></p>",T="5",U="a55fb718cb854bc0933877c493724583",V="款号",W="<p><span>入库单内</span><span style=\"text-decoration:underline ;\">入库清单</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">中包含的</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">&quot;款号&quot;去重</span><span>后换行拼接</span></p>",X="6",Y="a0a3e8ba43934134bf3da417206fbb63",Z="箱数",ba="<p><span>&quot;散装&quot;的没有箱数，不要以0填充</span></p>",bb="7",bc="5c967bc3fd1d4801af09ccfaf20b0dbf",bd="入库备注",be="<p><span>1.根据宽度限制字数展示，多余部分截断后拼'…'</span></p><p><span>2.鼠标移入：使用Tooltips展示全部文本</span></p>",bf="8",bg="64b507174e3f4197b390293aedd549a4",bh="打印预览",bi="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">分页方式</span></p><p><span>1.根据当前单据</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#6300BF;\">[子表1]入</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;text-decoration:underline ;color:#6300BF;\">库汇总</span><span>行数拆分成多个页面</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.调整行高使一张A5纸能够容纳下</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; i.</span><span style=\"color:#4B7902;\">首页</span><span>固定条数(由前端调整行高)</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; ii.</span><span style=\"color:#4B7902;\">其它页</span><span>均固定相同条数</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.</span><span style=\"color:#4B7902;\">仅首页</span><span>包含：标题、基础信息</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; c.每页均包含：清单信息、页脚</span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#027DB4;\"><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">标题</span></p><p><span>1.固定写作'成品入库单'</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">基础信息</span></p><p><span>1.入库单号、入库仓库、入库类型、入库时间、关联单据、入库备注：分别取自&quot;入库单&quot;对应的'成品入库单'、'入库仓库'、'入库类型'、'创建时间'、'关联单据'、'备注'</span></p><p><span>2.客户/供应商：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">字段名及取值：跟随&quot;入库类型&quot;</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.入库类型 == 采购入库：字段名称为&quot;供应商&quot;</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; a1.取当前入库单对应的'供应商'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; b.入库类型 ! = 采购入库：字段值为&quot;客户&quot;</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b1.取当前入库单对应的'客户'</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">清单信息</span></p><p><span>1.清单描述</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.数据来源：跟随</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#6300BF;\">[子表1]</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;text-decoration:underline ;color:#6300BF;\">入库汇总</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.数据排序按字段优先：款号&gt;&gt;颜色&gt;&gt;尺码</span></p><p><span>2.字段取值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.#：自动递增，不受分页影响</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.款号、款名、颜色、尺码、入库数量、单位：跟随当前入库单</span><span style=\"text-decoration:underline ;\">入库汇总</span><span>中同名字段</span></p><p><span>3.小计：合计</span><span style=\"font-family:'Nunito Sans Oblique', 'Nunito Sans', sans-serif;font-style:oblique;\">当前分页&nbsp; </span><span>的&quot;入库件数&quot;</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.标识处理：字体加粗</span></p><p><span>4.合计：合计</span><span style=\"font-family:'Nunito Sans Oblique', 'Nunito Sans', sans-serif;font-style:oblique;\">全部分页&nbsp; </span><span>的&quot;入库件数&quot;</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">页脚</span></p><p><span>1.制单人：取自&quot;入库单&quot;对应的'创建人'</span></p><p><span>2.采购员：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">仅&quot;入库类型==采购入库&quot;时展示</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.取当前入库单对应的&quot;关联单据&quot;于[成衣采购系统&gt;&gt;成品采购]中的'采购人'</span></p><p><span>3.打印日期：当前打印预览的日期</span></p><p><span>4.页码：包含当前页数和总页数</span></p>",bj="9",bk="83f18f77a5fb4a58b8282dcfe384375a",bl="+ 新增",bm="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">按钮逻辑</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.</span><span>打开{入库方式}弹窗</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.根据选择的&quot;入库方式&quot;跳转至对应的新增页</span></p>",bn="10",bo="fb20638ecfd74527846865696ce85ab2",bp="确认",bq="<p><span>根据选中的'入库方式'进入对应的入库新增页</span></p>",br="style",bs="baseStyle",bt="627587b6038d43cca051c114ac41ad32",bu="pageAlignment",bv="center",bw="fill",bx="fillType",by="solid",bz="color",bA=0xFFFFFFFF,bB="image",bC="imageAlignment",bD="near",bE="imageRepeat",bF="auto",bG="favicon",bH="sketchFactor",bI="0",bJ="colorStyle",bK="appliedColor",bL="fontName",bM="Applied Font",bN="borderWidth",bO="borderVisibility",bP="borderFill",bQ=0xFF797979,bR="cornerRadius",bS="cornerVisibility",bT="outerShadow",bU="on",bV=false,bW="offsetX",bX=5,bY="offsetY",bZ="blurRadius",ca="spread",cb="r",cc=0,cd="g",ce="b",cf="a",cg=0.349019607843137,ch="adaptiveStyles",ci="interactionMap",cj="diagram",ck="objects",cl="id",cm="9b55df87626541b1aaac0a19f0c90b0a",cn